y = sin(x);
subplot(2, 2, 1); %[output:0041e35e]
plot(x, y); %[output:0041e35e]
xlabel('X'); %[output:0041e35e]
ylabel('Sin(X)'); %[output:0041e35e]
title('Sine Function'); %[output:0041e35e]
